INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_infracoes' LIMIT 1), 'Quanto às infrações por excesso de velocidade previstas no CTB, analise as assertivas:

I. Transitar com velocidade superior à máxima em até 20% configura infração de natureza média.
II. Exceder o limite em mais de 20% até 50% caracteriza infração gravíssima.
III. Ultrapassar a velocidade máxima em mais de 50% constitui infração gravíssima, com penalidade de multa e suspensão do direito de dirigir.

Está CORRETO o que se afirma em:', 'Está correto o que se afirma em I, apenas.', 'Está correto o que se afirma em I e III, apenas.', 'Está correto o que se afirma em II e III, apenas.', 'Está correto o que se afirma em I, II e III.', NULL, 'B', 'assertivas', 'pegadinha_percentual', 4, '{"o_que_testa":"Gradação de gravidade das infrações de velocidade conforme percentual de excesso (art. 218).","fundamento_legal":"CTB, art. 218, I: até 20% — infração média. II: mais de 20% até 50% — infração grave. III: mais de 50% — infração gravíssima, com penalidade de multa (três vezes) e suspensão do direito de dirigir.","passo_a_passo":["I: Correta — inciso I do art. 218 (até 20% = média).","II: Errada — entre 20% e 50% é infração GRAVE, não gravíssima.","III: Correta — inciso III do art. 218 (acima de 50% = gravíssima com multa tripla e suspensão).","Gabarito: I e III = alternativa B."],"pegadinha":"Trocar infração grave (20% a 50%) por gravíssima — erro clássico em assertivas de velocidade.","macete":"Até 20% média | 20–50% grave | +50% gravíssima + suspensão.","estudo_reverso":["CTB art. 218","CTB art. 219","CTB art. 220"]}'::jsonb, '{"velocidade","art_218","gravidade","percentual"}'::text[]);